{
  "name": "site",
  "type": "module",
  "version": "0.0.1",
  "packageManager": "bun@1.3.13",
  "engines": {
    "node": ">=22.12.0"
  },
  "scripts": {
    "dev": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro dev",
    "build": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro build",
    "preview": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro preview",
    "check": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro check",
    "lint": "eslint src/scripts/**/*.ts",
    "astro": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro"
  },
  "dependencies": {
    "@astrojs/vercel": "^11.0.0",
    "astro": "^7.0.0"
  },
  "devDependencies": {
    "@astrojs/check": "^0.9.9",
    "cross-env": "10.1.0",
    "eslint": "^10.4.1",
    "typescript": "^6.0.3",
    "typescript-eslint": "^8.61.0"
  }
}

// @ts-check
import { defineConfig } from 'astro/config';

// https://astro.build/config
export default defineConfig({});

export interface Experiment {
  href: string;
  title: string;
  summary: string;
}

export const experiments: Experiment[] = [
  { href: '/cellular', title: 'cellular automata lab', summary: 'local rules, seeds, histories' },
  { href: '/complex', title: 'complex dynamics', summary: 'mandelbrot, julia, orbit traces' },
  { href: '/continued-fractions', title: 'continued fractions', summary: 'expansions, convergents, errors' },
  { href: '/chu-spaces', title: 'Chu spaces', summary: 'dual tables, tests, morphisms' },
  { href: '/dual', title: 'dual numbers', summary: 'nilpotents, tangents, automatic differentiation' },
  { href: '/fib/10', title: 'fibonacci', summary: 'static bigint sequence sample' },
  { href: '/groups', title: 'finite groups', summary: 'tables, classes, quotients' },
  { href: '/knot', title: 'knot diagrams', summary: 'crossings and polynomial sketches' },
  { href: '/padic', title: 'p-adics', summary: 'digits, inverses, hensel lifts' },
  { href: '/surreal', title: 'surreal numbers', summary: 'cuts and finite birthdays' },
  { href: '/symmetry', title: 'symmetry', summary: 'rotational mirror drawing' },
  { href: '/tropical', title: 'tropical geometry', summary: 'min-plus arithmetic and envelopes' },
  { href: '/voronoi', title: 'voronoi', summary: 'distance fields with mixed metrics' },
];

---
import '../styles/global.css';

interface Props {
  title?: string;
  description?: string;
}

const {
  title = 'incomplete.fun',
  description = 'A collection of fun, incomplete things.',
} = Astro.props;
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <link rel="icon" type="image/svg+xml" href="/favicon.svg" />
    <link rel="icon" href="/favicon.ico" />
    <meta name="viewport" content="width=device-width" />
    <meta name="description" content={description} />
    <title>{title}</title>
  </head>
  <body>
    <slot />
  </body>
</html>

---
import BaseLayout from './BaseLayout.astro';
import TopBar from '../components/TopBar.astro';

interface Props {
  name: string;
  description?: string;
  appId?: string;
}

const { name, description, appId } = Astro.props;
const title = `${name} - incomplete.fun`;
---

<BaseLayout title={title} description={description}>
  <div class="canvas-app" id={appId}>
    <TopBar name={name} back>
      <slot name="toolbar" />
    </TopBar>
    <slot />
  </div>
</BaseLayout>

:root {
  color-scheme: light dark;
  --bg: #fcfcfa;
  --fg: #171716;
  --muted: #716f68;
  --line: #e4e1d8;
  --wash: color-mix(in srgb, var(--bg) 94%, var(--fg));
  --accent: currentColor;
  --border: var(--line);
  --mono: inherit;
  --space: clamp(1rem, 4vw, 2.5rem);
  --measure: 38rem;
  font-family: ui-monospace, "SFMono-Regular", Menlo, Consolas, monospace;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #0f0f0e;
    --fg: #eeeeea;
    --muted: #9c9890;
    --line: #302e2a;
  }
}

* { box-sizing: border-box; }

body {
  margin: 0;
  background: var(--bg);
  color: var(--fg);
  font-size: 15px;
  line-height: 1.65;
  text-rendering: optimizeLegibility;
}

a {
  color: inherit;
  text-decoration: underline;
  text-decoration-color: var(--line);
  text-underline-offset: .25em;
}

a:hover { text-decoration-color: currentColor; }

h1, h2, h3, p, ul, ol { margin: 0 0 1rem; }

h1, h2, h3, strong { font-weight: 600; }

h1 {
  max-width: 13ch;
  font-size: clamp(2rem, 9vw, 5rem);
  line-height: .95;
  letter-spacing: -0.06em;
}

ul, ol { padding-left: 1.25rem; }

code {
  padding: .1em .3em;
  border: 1px solid var(--line);
  border-radius: 3px;
}

.app-shell, .canvas-app {
  min-height: 100dvh;
  background: var(--bg);
}

.app-shell { display: grid; grid-template-rows: auto 1fr; }
.canvas-app { display: flex; flex-direction: column; }

.topbar {
  display: flex;
  align-items: center;
  gap: 1rem;
  min-height: 3.25rem;
  padding: .75rem var(--space);
  border-bottom: 1px solid var(--line);
  flex-wrap: wrap;
}

.brand,
.topbar-title {
  text-decoration: none;
}

.brand { font-weight: 600; }

.topbar-title { color: var(--muted); }

.back-link {
  color: var(--muted);
  text-decoration: none;
}

.page {
  width: min(100%, var(--measure));
  margin: 0 auto;
  padding: calc(var(--space) * 1.4) var(--space);
}

.page-wide { --measure: 72rem; }

.home-hero {
  display: grid;
  gap: 1rem;
  margin-bottom: calc(var(--space) * 1.3);
}

.eyebrow,
.home-intro { color: var(--muted); }

.eyebrow {
  margin: 0;
  font-size: .78rem;
  letter-spacing: .08em;
  text-transform: uppercase;
}

.home-links {
  display: grid;
  gap: .5rem;
}

.home-link {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(8rem, 14rem);
  gap: 1rem;
  padding: .8rem 0;
  border-top: 1px solid var(--line);
  text-decoration: none;
}

.home-link:hover span { text-decoration: underline; text-underline-offset: .25em; }
.home-link small { color: var(--muted); }

@media (max-width: 34rem) {
  .home-link { grid-template-columns: 1fr; gap: .15rem; }
}

.canvas-stage {
  position: relative;
  flex: 1;
  overflow: hidden;
}

button, input {
  font: inherit;
  color: inherit;
}

.toolbar-button,
.metric-button {
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 999px;
  padding: .15rem .7rem;
  cursor: pointer;
}

.toolbar-button:hover,
.toolbar-button.is-active,
.metric-button:hover,
.metric-button.is-active {
  background: var(--fg);
  border-color: var(--fg);
  color: var(--bg);
}

select,
textarea,
input:not([type="checkbox"]):not([type="range"]):not([type="color"]) {
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 4px;
  color: var(--fg);
  font: inherit;
}

.control-label {
  display: inline-flex;
  align-items: center;
  gap: .4rem;
  color: var(--muted);
}

input[type="number"] {
  width: 3.5rem;
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 4px;
  padding: .1rem .35rem;
}

input[type="color"] {
  width: 2rem;
  height: 1.4rem;
  padding: 0;
  border: 1px solid var(--line);
  background: transparent;
}

input[type="checkbox"],
input[type="range"] {
  accent-color: var(--fg);
}

---
interface Props {
  name: string;
  back?: boolean;
}

const { name, back = false } = Astro.props;
---

<header class="topbar">
  {back && <a class="back-link" href="/" aria-label="Back to home">←</a>}
  <a class="brand" href="/" aria-label="incomplete.fun home">incomplete.fun</a>
  {name !== 'incomplete.fun' && <span class="topbar-title">/ {name}</span>}
  <slot />
</header>

---
import BaseLayout from './BaseLayout.astro';
import TopBar from '../components/TopBar.astro';

interface Props {
  name: string;
  back?: boolean;
  wide?: boolean;
  description?: string;
}

const { name, back = false, wide = false, description } = Astro.props;
const title = name === 'incomplete.fun' ? name : `${name} - incomplete.fun`;
---

<BaseLayout title={title} description={description}>
  <div class="app-shell">
    <TopBar name={name} back={back} />
    <main class={wide ? 'page page-wide' : 'page'}>
      <slot />
    </main>
  </div>
</BaseLayout>

---
import PageLayout from '../layouts/PageLayout.astro';
---

<PageLayout name="cellular automata lab" back wide>
  <p class="cellular-intro">Explore simple local rules by editing seed states, stepping time forward, and watching compact histories accumulate.</p>

  <section class="cellular-lab" id="cellular-app">
    <article class="cellular-card">
      <div class="cellular-card-head">
        <div>
          <h2>1D elementary rules</h2>
          <p>Each cell looks at its left, center, and right neighbors. The 8-bit rule number decides the next row.</p>
        </div>
        <div class="cellular-toolbar" aria-label="1D controls">
          <label>rule <input id="ca1-rule" type="number" min="0" max="255" value="30" /></label>
          <button class="toolbar-button" id="ca1-step" type="button">step</button>
          <button class="toolbar-button" id="ca1-play" type="button">play</button>
          <button class="toolbar-button" id="ca1-single" type="button">single seed</button>
          <button class="toolbar-button" id="ca1-random" type="button">random</button>
          <button class="toolbar-button" id="ca1-clear" type="button">clear</button>
        </div>
      </div>

      <div class="cellular-rule" id="ca1-rule-table" aria-live="polite"></div>
      <div class="cellular-canvas-wrap">
        <canvas id="ca1-canvas" width="960" height="560" aria-label="1D automaton history"></canvas>
      </div>
      <p class="cellular-hint">Click the top row to toggle cells and restart the visible history from that edited seed.</p>
    </article>

    <article class="cellular-card">
      <div class="cellular-card-head">
        <div>
          <h2>2D outer-totalistic rules</h2>
          <p>Birth/survival rules use the count of live neighbors around each square. Start with Conway's Life, then try variants.</p>
        </div>
        <div class="cellular-toolbar" aria-label="2D controls">
          <label>
            rule
            <select id="ca2-rule">
              <option value="life">Life B3/S23</option>
              <option value="highlife">HighLife B36/S23</option>
              <option value="seeds">Seeds B2/S</option>
              <option value="daynight">Day &amp; Night B3678/S34678</option>
              <option value="majority">Majority B5678/S45678</option>
            </select>
          </label>
          <button class="toolbar-button" id="ca2-step" type="button">step</button>
          <button class="toolbar-button" id="ca2-play" type="button">play</button>
          <button class="toolbar-button" id="ca2-random" type="button">random</button>
          <button class="toolbar-button" id="ca2-clear" type="button">clear</button>
        </div>
      </div>

      <div class="cellular-2d-grid">
        <div>
          <div class="cellular-canvas-wrap">
            <canvas id="ca2-canvas" width="768" height="480" aria-label="2D automaton grid"></canvas>
          </div>
          <p class="cellular-hint">Click or drag on the grid to draw live cells. Edges wrap like a torus.</p>
        </div>
        <aside class="cellular-history-panel">
          <h3>history</h3>
          <canvas id="ca2-history" width="280" height="280" aria-label="2D automaton population history"></canvas>
          <div class="cellular-stats" id="ca2-stats" aria-live="polite"></div>
        </aside>
      </div>
    </article>
  </section>
</PageLayout>

<style>
  .cellular-intro,
  .cellular-hint,
  .cellular-card p,
  .cellular-stats { color: var(--muted); }

  .cellular-lab { display: grid; gap: 1rem; }

  .cellular-card {
    border: 1px solid var(--line);
    padding: 1rem;
    display: grid;
    gap: 1rem;
  }

  .cellular-card-head {
    display: grid;
    grid-template-columns: minmax(0, 1fr) auto;
    gap: 1rem;
    align-items: start;
  }

  .cellular-card h2,
  .cellular-card h3 { font-size: 1rem; margin-bottom: 0.25rem; }

  .cellular-toolbar {
    display: flex;
    flex-wrap: wrap;
    justify-content: end;
    gap: 0.45rem;
    align-items: center;
  }

  .cellular-toolbar label {
    display: inline-flex;
    align-items: center;
    gap: 0.35rem;
    color: var(--muted);
  }

  .cellular-toolbar input,
  .cellular-toolbar select {
    background: transparent;
    border: 1px solid var(--line);
    border-radius: 4px;
    color: var(--fg);
    padding: 0.15rem 0.35rem;
    font: inherit;
  }

  .cellular-toolbar input { width: 4.25rem; }

  .cellular-rule {
    display: grid;
    grid-template-columns: repeat(8, minmax(4.25rem, 1fr));
    gap: 0.35rem;
    overflow-x: auto;
    font-size: 0.78rem;
  }

  .rule-chip {
    border: 1px solid var(--line);
    padding: 0.35rem;
    display: grid;
    gap: 0.25rem;
    justify-items: center;
  }

  .rule-cells { display: grid; grid-template-columns: repeat(3, 0.7rem); gap: 0.12rem; }
  .rule-cell, .rule-out { width: 0.7rem; height: 0.7rem; border: 1px solid var(--line); }
  .rule-out { width: 1rem; }
  .is-alive { background: var(--fg); }

  .cellular-canvas-wrap {
    border: 1px solid var(--line);
    overflow: auto;
    background: color-mix(in srgb, var(--bg) 94%, var(--fg));
  }

  .cellular-canvas-wrap canvas {
    display: block;
    width: 100%;
    height: auto;
    image-rendering: pixelated;
    cursor: crosshair;
  }

  .cellular-2d-grid {
    display: grid;
    grid-template-columns: minmax(0, 1fr) minmax(16rem, 18rem);
    gap: 1rem;
  }

  .cellular-history-panel {
    border: 1px solid var(--line);
    padding: 0.75rem;
  }

  #ca2-history {
    width: 100%;
    height: auto;
    border: 1px solid var(--line);
    image-rendering: pixelated;
    background: color-mix(in srgb, var(--bg) 94%, var(--fg));
  }

  .cellular-stats { font-size: 0.85rem; margin-top: 0.75rem; }

  @media (max-width: 56rem) {
    .cellular-card-head,
    .cellular-2d-grid { grid-template-columns: 1fr; }
    .cellular-toolbar { justify-content: start; }
    .cellular-rule { grid-template-columns: repeat(8, 4.25rem); }
  }
</style>

<script>
  import '../scripts/cellular.ts';
</script>

---
import CanvasLayout from '../layouts/CanvasLayout.astro';
---

<CanvasLayout name="complex dynamics" appId="complex-app">
  <Fragment slot="toolbar">
    <button class="toolbar-button is-active" id="complex-mandelbrot" type="button">mandelbrot</button>
    <button class="toolbar-button" id="complex-julia" type="button">julia</button>

    <label class="control-label">
      c=
      <input id="complex-c-real" type="number" step="0.001" value="-0.800" />
      <input id="complex-c-imag" type="number" step="0.001" value="0.156" />
    </label>

    <label class="control-label">
      iter
      <input id="complex-iterations" type="range" min="40" max="600" step="10" value="180" />
      <span id="complex-iteration-value">180</span>
    </label>

    <button class="toolbar-button" id="complex-reset" type="button">reset</button>
    <span class="complex-help">wheel zoom · drag pan · click Mandelbrot to pick Julia c</span>
  </Fragment>

  <div id="complex-readout">
    <span id="complex-coords">z = 0 + 0i</span>
    <span id="complex-status">ready</span>
  </div>

  <div class="canvas-stage" id="complex-stage">
    <canvas id="complex-canvas"></canvas>
    <canvas id="complex-orbit"></canvas>
  </div>
</CanvasLayout>

<style>
  #complex-c-real,
  #complex-c-imag { width: 5.5rem; }

  #complex-iterations { width: 6rem; }

  #complex-iteration-value {
    min-width: 2.25rem;
    color: var(--muted);
    font-variant-numeric: tabular-nums;
  }

  .complex-help {
    margin-left: auto;
    color: var(--muted);
    font-size: .78rem;
  }

  #complex-readout {
    display: flex;
    justify-content: space-between;
    gap: 1rem;
    padding: .35rem var(--space);
    border-bottom: 1px solid var(--line);
    color: var(--muted);
    font-size: .78rem;
    font-variant-numeric: tabular-nums;
  }

  #complex-status { text-align: right; }

  #complex-stage {
    cursor: crosshair;
    touch-action: none;
  }

  #complex-canvas,
  #complex-orbit {
    position: absolute;
    inset: 0;
    display: block;
    width: 100%;
    height: 100%;
  }

  #complex-orbit { pointer-events: none; }
</style>

<script>
  import '../scripts/complex.ts';
</script>

---
import CanvasLayout from '../layouts/CanvasLayout.astro';
---

<CanvasLayout name="voronoi" appId="voronoi-app">
  <Fragment slot="toolbar">
    <span class="toolbar-separator" aria-hidden="true">|</span>
    <button class="metric-button" type="button" data-metric="minkowski05" title="minkowski p=1/2 (star)">L½</button>
    <button class="metric-button" type="button" data-metric="manhattan" title="manhattan (diamond)">L1</button>
    <button class="metric-button" type="button" data-metric="euclidean" title="euclidean (circular)">L2</button>
    <button class="metric-button" type="button" data-metric="minkowski3" title="minkowski p=3 (rounded square)">L3</button>
    <button class="metric-button" type="button" data-metric="chebyshev" title="chebyshev (square)">L∞</button>

    <span id="voronoi-help">click to place · right-click removes</span>
    <button class="toolbar-button" id="voronoi-clear" type="button">clear</button>
  </Fragment>

  <div id="voronoi-hover-row">
    <span id="voronoi-coords">(0, 0)</span>
    <div id="voronoi-distances"></div>
  </div>

  <div class="canvas-stage" id="voronoi-stage">
    <canvas id="voronoi-gl"></canvas>
    <canvas id="voronoi-markers"></canvas>
    <div id="voronoi-webgl-error" role="status">WebGL2 is required for this experiment.</div>
    <div id="voronoi-empty">
      <span>click to place points</span>
      <span class="small-muted">each point uses its own distance metric</span>
    </div>
  </div>
</CanvasLayout>

<style>
  .toolbar-separator {
    color: var(--line);
  }

  #voronoi-help {
    color: var(--muted);
    font-size: 0.75rem;
    margin-left: auto;
  }

  #voronoi-hover-row {
    display: grid;
    grid-template-columns: 6.5rem minmax(0, 1fr);
    column-gap: 0.75rem;
    padding: 0 var(--space);
    border-bottom: 1px solid var(--line);
    font-size: 0.78rem;
    line-height: 1.25;
    min-height: 1.9rem;
    max-height: 6.5rem;
    overflow-x: hidden;
    overflow-y: auto;
    font-variant-numeric: tabular-nums;
  }

  #voronoi-coords {
    color: var(--muted);
    white-space: nowrap;
    padding-top: 0.35rem;
    visibility: hidden;
  }

  #voronoi-distances {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(18rem, 1fr));
    gap: 0.25rem 0.75rem;
    min-width: 0;
    padding: 0.25rem 0;
  }

  #voronoi-stage {
    cursor: crosshair;
    touch-action: none;
  }

  #voronoi-gl,
  #voronoi-markers {
    position: absolute;
    inset: 0;
    display: block;
  }

  #voronoi-markers { pointer-events: none; }

  #voronoi-webgl-error,
  #voronoi-empty {
    position: absolute;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    gap: 0.4rem;
    color: var(--muted);
    pointer-events: none;
  }

  #voronoi-webgl-error { display: none; }
  .small-muted { font-size: 0.75rem; }
</style>

<style is:global>
  .distance-entry {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    min-width: 0;
    color: var(--muted);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .distance-entry.is-winner {
    color: var(--fg);
    font-weight: bold;
  }

  .distance-dot {
    display: inline-block;
    width: 7px;
    height: 7px;
    border-radius: 50%;
    flex-shrink: 0;
  }

  .distance-label {
    color: var(--muted);
    font-size: 0.72rem;
    flex-shrink: 0;
  }

  .distance-value {
    overflow: hidden;
    text-overflow: ellipsis;
  }
</style>

<script>
  import '../scripts/voronoi.ts';
</script>

---
import PageLayout from '../layouts/PageLayout.astro';
---

<PageLayout name="p-adic calculator" back wide>
  <p class="padic-intro">Explore rational numbers by their base-p digits extending to the left.</p>

  <section class="padic-grid" id="padic-app">
      <form class="padic-card" id="padic-expansion-form">
        <h2>rational expansion</h2>
        <label>
          prime p
          <input id="padic-prime" type="number" min="2" max="97" step="1" value="5" />
        </label>
        <label>
          rational number
          <input id="padic-rational" type="text" value="1/3" inputmode="text" />
        </label>
        <label>
          digits
          <input id="padic-digits" type="number" min="1" max="40" step="1" value="16" />
        </label>
        <button class="toolbar-button" type="submit">compute</button>
        <div class="padic-output" id="padic-expansion-output" aria-live="polite"></div>
      </form>

      <form class="padic-card" id="padic-inverse-form">
        <h2>modular inverse</h2>
        <label>
          a
          <input id="padic-inverse-a" type="text" value="7" />
        </label>
        <label>
          modulus p^k
          <span class="padic-inline-inputs">
            <input id="padic-inverse-p" type="number" min="2" max="97" step="1" value="5" aria-label="prime p" />
            <input id="padic-inverse-k" type="number" min="1" max="30" step="1" value="6" aria-label="exponent k" />
          </span>
        </label>
        <button class="toolbar-button" type="submit">invert</button>
