  .cf-card label, .cf-rational-fields, .cf-quadratic-fields { display: grid; gap: .3rem; color: var(--muted); }
  .cf-rational-fields, .cf-quadratic-fields { grid-template-columns: repeat(auto-fit, minmax(5rem, 1fr)); }
  .cf-card input, .cf-card select { width: 100%; background: transparent; color: var(--fg); border: 1px solid var(--line); border-radius: 4px; padding: .35rem .45rem; font: inherit; }
  .cf-output, .cf-table-wrap { overflow-x: auto; }
  .cf-explain { display: grid; gap: .6rem; color: var(--muted); }
  .cf-explain p { margin: 0; }
  .cf-expanded { font-size: 1.05rem; line-height: 2; }
  .cf-nested { display: inline-block; white-space: nowrap; }
  .cf-frac { display: inline-grid; grid-template-rows: auto auto; vertical-align: middle; text-align: center; margin: 0 .08rem; }
